const targets = $input.all().map(i => i.json);

// Mobile User-Agents only — widget renders only on mobile
const mobileUAs = [
  'Mozilla/5.0 (iPhone; CPU iPhone OS 26_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/26.0 Mobile/15E148 Safari/604.1',
  'Mozilla/5.0 (Linux; Android 15; SM-S928B) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.7535.50 Mobile Safari/537.36',
  'Mozilla/5.0 (Linux; Android 16; Pixel 9 Pro) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.7535.50 Mobile Safari/537.36',
  'Mozilla/5.0 (iPhone; CPU iPhone OS 26_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/26.0 Mobile/15E148 Safari/604.1'
];

const referers = [
  'https://www.google.com/',
  'https://yandex.ru/',
  'https://www.bing.com/',
  'https://dzen.ru/',
  ''
];

const TIMEZONE_MAP = {
  'FI': 3, 'RU': 3, 'KZ': 6, 'DE': 2, 'US': -5,
  'UA': 3, 'BY': 3, 'PL': 2, 'TR': 3, 'JP': 9,
  'IN': 5, 'BR': -3, 'GB': 1, 'FR': 2, 'IT': 2,
  'ES': 2, 'PT': 1, 'NL': 2, 'SE': 2, 'NO': 2,
  'CZ': 2, 'AT': 2, 'CH': 2, 'BE': 2, 'RO': 3,
  'TH': 7, 'VN': 7, 'ID': 7, 'PH': 8, 'MY': 8
};

const LANG_MAP = {
  'FI': 'fi-FI,fi;q=0.9,en;q=0.8',
  'RU': 'ru-RU,ru;q=0.9,en;q=0.8',
  'KZ': 'kk-KZ,kk;q=0.9,ru-RU;q=0.8,ru;q=0.7',
  'DE': 'de-DE,de;q=0.9,en;q=0.8',
  'US': 'en-US,en;q=0.9',
  'UA': 'uk-UA,uk;q=0.9,ru;q=0.8',
  'BY': 'ru-BY,ru;q=0.9,en;q=0.8',
  'PL': 'pl-PL,pl;q=0.9,en;q=0.8',
  'TR': 'tr-TR,tr;q=0.9,en;q=0.8',
  'JP': 'ja-JP,ja;q=0.9,en;q=0.8',
  'IN': 'hi-IN,hi;q=0.9,en-IN;q=0.8,en;q=0.7',
  'BR': 'pt-BR,pt;q=0.9,en;q=0.8',
  'GB': 'en-GB,en;q=0.9',
  'FR': 'fr-FR,fr;q=0.9,en;q=0.8',
  'IT': 'it-IT,it;q=0.9,en;q=0.8',
  'ES': 'es-ES,es;q=0.9,en;q=0.8',
  'TH': 'th-TH,th;q=0.9,en;q=0.8',
  'VN': 'vi-VN,vi;q=0.9,en;q=0.8'
};

// DataImpulse proxy: auto-generate proxy URL from bot_config + country_code
// If scan_target has manual proxy_url — use it as override
// buildProxyUrl(target, cc) — with geo for render
// buildProxyUrl(target, '') — without geo for page fetch (some sites block geo IPs)
function buildProxyUrl(target, cc) {
  if (target.proxy_url && target.proxy_url.trim()) {
    return target.proxy_url.trim();
  }
  const login = (target.di_login || '').trim();
  const pass = (target.di_password || '').trim();
  const host = (target.di_host || 'gw.dataimpulse.com').trim();
  const port = (target.di_port || '823').toString().trim();
  if (!login || !pass) return '';
  if (cc) {
    const userWithGeo = login + '__cr.' + cc.toLowerCase();
    const encUser = encodeURIComponent(userWithGeo);
    const encPass = encodeURIComponent(pass);
    return `http://${encUser}:${encPass}@${host}:${port}`;
  }
  const encUser = encodeURIComponent(login);
  const encPass = encodeURIComponent(pass);
  return `http://${encUser}:${encPass}@${host}:${port}`;
}

return targets.map(t => {
  const cc = (t.country_code || '').trim();
  const proxyUrlGeo = buildProxyUrl(t, cc);
  const proxyUrlNoGeo = buildProxyUrl(t, '');
  return {
    json: {
      target_id: t.id,
      site_url: ((s) => s.startsWith('http') ? s : 'https://' + s)((t.site_url || '').trim()),
      country_code: cc,
      proxy_url: proxyUrlGeo,
      proxy_url_page: proxyUrlNoGeo,
      proxy_type: proxyUrlGeo.startsWith('socks') ? 'socks5' : 'http',
      proxy_auto: !t.proxy_url || !t.proxy_url.trim(),
      user_agent: mobileUAs[Math.floor(Math.random() * mobileUAs.length)],
      referer: referers[Math.floor(Math.random() * referers.length)],
      timezone: t.timezone || TIMEZONE_MAP[cc] || 3,
      accept_language: t.accept_language || LANG_MAP[cc] || 'en-US,en;q=0.9',
      cached_render_domain: t.render_domain || null,
      cached_block_uuids: t.block_uuids || null,
      cached_extra_params: t.extra_params || null,
      cached_geozo_block_id: t.geozo_block_id || null
    }
  };
});

// Pick a random FRESH article link from the homepage HTML
// Prefers articles published within the last 10 days (more likely to have geozo widget)
// Falls back to all articles if no fresh ones found
const items = $input.all();
const scanRequests = $('Prepare Scan Requests').all().map(i => i.json);
const results = [];

const FRESH_DAYS = 10;
const now = new Date();

// Try to extract a date from a URL path
// Supports: /2025/07/15/slug, /2025/07/slug, /2025-07-15-slug
function parseDateFromUrl(url) {
  // Pattern: /YYYY/MM/DD/
  let m = url.match(/\/(20\d{2})\/(0[1-9]|1[0-2])\/(0[1-9]|[12]\d|3[01])(\/|$)/);
  if (m) return new Date(parseInt(m[1]), parseInt(m[2]) - 1, parseInt(m[3]));
  // Pattern: /YYYY/MM/ (assume 1st of month)
  m = url.match(/\/(20\d{2})\/(0[1-9]|1[0-2])(\/|$)/);
  if (m) return new Date(parseInt(m[1]), parseInt(m[2]) - 1, 1);
  // Pattern: /YYYY-MM-DD- in slug
  m = url.match(/\/(20\d{2})-(0[1-9]|1[0-2])-(0[1-9]|[12]\d|3[01])-/);
  if (m) return new Date(parseInt(m[1]), parseInt(m[2]) - 1, parseInt(m[3]));
  return null;
}

function daysBetween(d1, d2) {
  return Math.abs(d1 - d2) / (1000 * 60 * 60 * 24);
}

for (let idx = 0; idx < items.length; idx++) {
  const input = items[idx].json;
  const html = String(input.data || input.body || '');
  const scanReq = idx < scanRequests.length ? scanRequests[idx] : scanRequests[0];
  const siteUrl = scanReq.site_url;

  // Detect if site_url is a homepage (no meaningful path)
  let isHomepage = false;
  try {
    const pathPart = siteUrl.replace(/^https?:\/\/[^/]+/, '');
    isHomepage = !pathPart || pathPart === '/' || pathPart === '/index.html' || pathPart === '/index.php';
  } catch(e) { isHomepage = false; }

  if (!isHomepage || html.length < 100) {
    results.push({ json: { ...input, article_url: siteUrl, is_random_article: false } });
    continue;
  }

  // Parse all <a href="..."> links from homepage
  const baseMatch = siteUrl.match(/^(https?:\/\/[^/]+)/);
  const baseDomain = baseMatch ? baseMatch[1] : '';
  const hostname = baseDomain.replace(/^https?:\/\//, '');
  const links = new Set();

  const linkRegex = /<a[^>]*href=["']([^"'#]+)["'][^>]*>/gi;
  let lm;
  while ((lm = linkRegex.exec(html)) !== null) {
    let href = lm[1].replace(/&amp;/g, '&');
    if (href.startsWith('//')) href = 'https:' + href;
    if (href.startsWith('/')) href = baseDomain + href;
    if (!href.startsWith('http')) continue;
    // Strict domain check: extract only the hostname from the link, ignore query params
    const linkHostMatch = href.match(/^https?:\/\/([^/?#]+)/);
    const linkHost = linkHostMatch ? linkHostMatch[1] : '';
    if (!linkHost.includes(hostname) && !hostname.includes(linkHost)) continue;
    const path = href.replace(/^https?:\/\/[^/]+/, '').replace(/[?#].*$/, '');
    if (!path || path === '/' || path.length < 5) continue;
    if (/\/(wp-|feed|admin|login|register|search|tag\/|category\/|author\/|page\/|\?)/i.test(path)) continue;
    const segments = path.split('/').filter(Boolean);
    if (segments.length >= 2 || (segments.length === 1 && segments[0].length > 10)) {
      links.add(href.split('?')[0].split('#')[0]);
    }
  }

  const articleLinks = Array.from(links);

  if (articleLinks.length === 0) {
    results.push({ json: { ...input, article_url: siteUrl, is_random_article: false } });
    continue;
  }

  // Separate fresh articles (with parseable date <= FRESH_DAYS old) from the rest
  const freshArticles = [];
  const undatedArticles = [];
  for (const link of articleLinks) {
    const d = parseDateFromUrl(link);
    if (d && daysBetween(now, d) <= FRESH_DAYS) {
      freshArticles.push(link);
    } else if (!d) {
      undatedArticles.push(link);
    }
    // dated but old — skip (least likely to have widget)
  }

  // Priority: fresh dated articles > undated articles > all articles
  let pool = freshArticles.length > 0 ? freshArticles
           : undatedArticles.length > 0 ? undatedArticles
           : articleLinks;
  const selectionSource = freshArticles.length > 0 ? 'fresh'
                        : undatedArticles.length > 0 ? 'undated'
                        : 'all';

  const randomArticle = pool[Math.floor(Math.random() * pool.length)];
  results.push({ json: {
    ...input,
    article_url: randomArticle,
    homepage_url: siteUrl,
    is_random_article: true,
    articles_found: articleLinks.length,
    fresh_articles_found: freshArticles.length,
    selection_source: selectionSource
  }});
}

return results;

// Process ALL proxy responses — match metadata by site_url, not by index
const items = $input.all();

// Safely get upstream node data (may not exist in execution path)
let scanRequests = [];
let articleItems = [];
try { scanRequests = $('Prepare Scan Requests').all().map(i => i.json); } catch(e) { /* node not in path */ }
try { articleItems = $('Pick Random Article').all().map(i => i.json); } catch(e) { /* node not in path */ }

// Build lookup maps for metadata (by site_url)
const articleByUrl = new Map();
const scanReqByUrl = new Map();
articleItems.forEach(j => {
  const baseMatch = (j.site_url || j.homepage_url || '').match(/^(https?:\/\/[^/]+)/);
  const key = baseMatch ? baseMatch[1] : (j.site_url || '');
  if (key) articleByUrl.set(key, j);
});
scanRequests.forEach(sr => {
  const baseMatch = (sr.site_url || '').match(/^(https?:\/\/[^/]+)/);
  const key = baseMatch ? baseMatch[1] : sr.site_url;
  if (key) scanReqByUrl.set(key, sr);
});

const MAX_REFRESHES = 5;

function genUuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

const results = [];

// Track which scanRequests were matched (to handle true-branch items without site_url)
const matchedSites = new Set();
// First pass: process items that have site_url metadata (false-branch items)
// Second pass: process items without site_url (true-branch HTTP responses)
const itemsWithMeta = [];
const itemsWithoutMeta = [];
for (const item of items) {
  if (item.json.site_url || item.json.article_url || item.json.homepage_url) {
    itemsWithMeta.push(item);
  } else {
    itemsWithoutMeta.push(item);
  }
}

// Process all items, using metadata from the item itself or from lookup maps
const allItems = [...itemsWithMeta, ...itemsWithoutMeta];
// For true-branch items (HTTP responses without metadata), assign unmatched scan requests
const unmatchedReqs = scanRequests.filter(sr => {
  const baseMatch = (sr.site_url || '').match(/^(https?:\/\/[^/]+)/);
  const key = baseMatch ? baseMatch[1] : sr.site_url;
  // Check if any items with metadata already cover this site
  return !itemsWithMeta.some(item => {
    const itemUrl = item.json.site_url || item.json.homepage_url || '';
    const itemBase = (itemUrl.match(/^(https?:\/\/[^/]+)/) || [null, itemUrl])[1];
    return itemBase === key;
  });
});

let unmatchedIdx = 0;

for (const item of allItems) {
  const input = item.json;
  const html = input.data || input.body || (typeof input === 'string' ? input : '');

  // Determine metadata: from item itself or from lookup
  let siteUrl, geo, proxyUrl, userAgent, tz, acceptLang;

  if (input.site_url || input.homepage_url) {
    // Item has metadata (false-branch or Pick Random Article output)
    const baseMatch = (input.site_url || input.homepage_url || '').match(/^(https?:\/\/[^/]+)/);
    const baseUrl = baseMatch ? baseMatch[1] : (input.site_url || '');
    const scanReq = scanReqByUrl.get(baseUrl) || scanRequests[0];
    const articleItem = articleByUrl.get(baseUrl) || input;
    siteUrl = articleItem.article_url || input.site_url || scanReq.site_url;
    geo = input.country_code || scanReq.country_code;
    proxyUrl = input.proxy_url || scanReq.proxy_url;
    userAgent = input.user_agent || scanReq.user_agent;
    tz = input.timezone || scanReq.timezone || 3;
    acceptLang = input.accept_language || scanReq.accept_language || 'en-US,en;q=0.9';
    matchedSites.add(baseUrl);
  } else {
    // HTTP response without metadata (true-branch) — use unmatched scan request
    const scanReq = unmatchedIdx < unmatchedReqs.length ? unmatchedReqs[unmatchedIdx] : scanRequests[0];
    const baseMatch = (scanReq.site_url || '').match(/^(https?:\/\/[^/]+)/);
    const baseUrl = baseMatch ? baseMatch[1] : scanReq.site_url;
    const articleItem = articleByUrl.get(baseUrl) || {};
    siteUrl = articleItem.article_url || scanReq.site_url;
    geo = scanReq.country_code;
    proxyUrl = scanReq.proxy_url;
    userAgent = scanReq.user_agent;
    tz = scanReq.timezone || 3;
    acceptLang = scanReq.accept_language || 'en-US,en;q=0.9';
    unmatchedIdx++;
  }

  if (input.error || input.code >= 400) {
    results.push({ json: {
      site_url: siteUrl,
      country_code: geo,
      widget_found: false,
      block_ids: [],
      error: input.error || `HTTP ${input.code || 'unknown'}`,
      proxy_url: proxyUrl,
      scanned_at: $now.toISO()
    }});
    continue;
  }

  // --- Always use render.geozo.com as render domain ---
  const renderDomain = 'render.geozo.com';

  // Find data-gz-block UUIDs
  const blockIds = [];
  const seen = new Set();
  const blockRegex1 = /data-gz-block=["']([0-9a-f-]{36})["']/gi;
  let m;
  while ((m = blockRegex1.exec(html)) !== null) {
    if (!seen.has(m[1])) { seen.add(m[1]); blockIds.push(m[1]); }
  }
  const blockRegex2 = /data-gz-block=\\+["']([0-9a-f-]{36})\\+["']/gi;
  while ((m = blockRegex2.exec(html)) !== null) {
    if (!seen.has(m[1])) { seen.add(m[1]); blockIds.push(m[1]); }
  }

  // Parse extra data-* attributes from EACH block div (different blocks may have different params)
  const extraParamsByBlock = {};
  const blockDivRegex = /<div[^>]*data-gz-block=["']([0-9a-f-]{36})["']([^>]*)>/gi;
  let bdm;
  while ((bdm = blockDivRegex.exec(html)) !== null) {
    const bUuid = bdm[1];
    const attrs = bdm[2] || '';
    const params = {};
    const attrRegex = /data-([a-z0-9_]+)=["']([^"']+)["']/gi;
    let am;
    while ((am = attrRegex.exec(attrs)) !== null) {
      if (am[1] !== 'gz-block') params[am[1]] = am[2];
    }
    extraParamsByBlock[bUuid] = params;
  }

  // Fallback: if no block UUIDs found in HTML, use cached from DB
  const siteBase = (siteUrl.match(/^(https?:\/\/[^/]+)/) || [null, siteUrl])[1];
  const cachedReq = scanReqByUrl.get(siteBase) || scanRequests[0] || {};
  if (blockIds.length === 0 && cachedReq.cached_block_uuids) {
    try {
      const cached = typeof cachedReq.cached_block_uuids === 'string' ? JSON.parse(cachedReq.cached_block_uuids) : cachedReq.cached_block_uuids;
      const arr = Array.isArray(cached) ? cached : [cached];
      arr.forEach(id => {
        const s = String(id).trim();
        if (/^[0-9a-f-]{36}$/.test(s) && !seen.has(s)) { seen.add(s); blockIds.push(s); }
      });
    } catch(e) { /* ignore parse errors */ }
  }

  if (blockIds.length === 0) {
    results.push({ json: {
      site_url: siteUrl,
      country_code: geo,
      widget_found: false,
      block_ids: [],
      render_url: '',
      render_domain: renderDomain,
      proxy_url: proxyUrl,
      user_agent: userAgent,
      accept_language: acceptLang,
      scanned_at: $now.toISO()
    }});
    continue;
  }

  // Generate render URLs for ALL blocks × MAX_REFRESHES rounds
  for (let bIdx = 0; bIdx < blockIds.length; bIdx++) {
    const blockUuid = blockIds[bIdx];
    const blockExtraParams = extraParamsByBlock[blockUuid] || {};
    for (let round = 0; round < MAX_REFRESHES; round++) {
      const surferUuid = genUuid();
      const pageLoadUuid = genUuid();
      let extraQs = '';
      for (const [k, v] of Object.entries(blockExtraParams)) {
        extraQs += `&${encodeURIComponent(k)}=${encodeURIComponent(v)}`;
      }
      const renderUrl = `https://${renderDomain}/v5/render?surfer_uuid=${surferUuid}&referrer=${encodeURIComponent(siteUrl)}&pre_referrer=${encodeURIComponent(siteUrl)}&time_zone=${tz}&page_load_uuid=${pageLoadUuid}&page_depth=1&block_uuid=${blockUuid}&refresh_depth=${round + 1}${extraQs}`;
      results.push({ json: {
        site_url: siteUrl,
        country_code: geo,
        widget_found: true,
        block_ids: blockIds,
        current_block_uuid: blockUuid,
        block_index: bIdx + 1,
        total_blocks: blockIds.length,
        render_url: renderUrl,
        render_domain: renderDomain,
        refresh_round: round + 1,
        proxy_url: proxyUrl,
        user_agent: userAgent,
        accept_language: acceptLang,
        scanned_at: $now.toISO()
      }});
    }
  }
}

if (results.length === 0) {
  return [{ json: { widget_found: false, block_ids: [], error: 'No valid responses from any proxy' } }];
}
return results;

// Parse teasers from render HTML — process each site separately
// Split by RENDER_SEPARATOR to get correct per-render positions
const allInputs = $input.all();
const results = [];

function parseSingleRender(html) {
  const teasers = [];
  let position = 0;
  for (const m of html.matchAll(/<a\b([^>]*)>([\s\S]*?)<\/a>/gi)) {
    const attrs = m[1];
    const inner = m[2];
    const classMatch = attrs.match(/class=["']([^"']+)["']/i);
    if (!classMatch || !classMatch[1].includes('media')) continue;

    const hrefMatch = attrs.match(/href=["']([^"']+)["']/i);
    const clickUrl = hrefMatch ? hrefMatch[1].replace(/&amp;/g, '&') : '';

    const titleMatch = inner.match(/class=["'][^"']*media__title[^"']*["'][^>]*>\s*([\s\S]*?)\s*<\/\w+>/i);
    const title = titleMatch ? titleMatch[1].replace(/<[^>]+>/g, '').trim() : '';
    if (title.length <= 3) continue;

    position++;

    let mediaId = null;
    const mediaMatch = clickUrl.match(/media=(\d+)/);
    if (mediaMatch) mediaId = mediaMatch[1];

    let imageUrl = null;
    const bgMatch = inner.match(/class=["'][^"']*media__img[^"']*["'][^>]*style=["'][^"']*background-image:\s*url\(['\"]?([^'\")]+)['\"]?\)/i);
    if (bgMatch) {
      imageUrl = bgMatch[1].replace(/&amp;/g, '&').replace(/&#39;/g, '').replace(/&quot;/g, '').replace(/^['"]|['"]$/g, '');
      if (!imageUrl.startsWith('http')) imageUrl = null;
    }
    if (!imageUrl) {
      const imgMatch = inner.match(/<img[^>]*src=["']([^"']+)["']/i);
      if (imgMatch) {
        imageUrl = imgMatch[1].replace(/&amp;/g, '&');
        if (!imageUrl.startsWith('http')) imageUrl = null;
      }
    }

    const sdMatch = inner.match(/class=["'][^"']*media__shortDesc[^"']*["'][^>]*>\s*([\s\S]*?)\s*<\/\w+>/i);
    const shortDesc = sdMatch ? sdMatch[1].replace(/<[^>]+>/g, '').trim() : null;
    const fdMatch = inner.match(/class=["'][^"']*media__fullDesc[^"']*["'][^>]*>\s*([\s\S]*?)\s*<\/\w+>/i);
    const fullDesc = fdMatch ? fdMatch[1].replace(/<[^>]+>/g, '').trim() : null;
    const btnMatch = inner.match(/class=["'][^"']*media__btn[^"']*["'][^>]*>\s*([\s\S]*?)\s*<\/\w+>/i);
    const btnText = btnMatch ? btnMatch[1].replace(/<[^>]+>/g, '').trim() : null;

    teasers.push({ position, title, media_id: mediaId, click_url: clickUrl || null, image_url: imageUrl, short_description: shortDesc, full_description: fullDesc, button_text: btnText });
  }
  return teasers;
}

for (const inputItem of allInputs) {
  const input = inputItem.json;
  const renderHtml = input.data || '';
  const rawSiteUrl = input.site_url;
  const siteUrlMatch = rawSiteUrl.match(/^(https?:\/\/[^/]+)/);
  const siteUrl = siteUrlMatch ? siteUrlMatch[1] : rawSiteUrl;
  const geo = input.country_code;
  const renderDomain = input.render_domain || '';

  if (!renderHtml || renderHtml.length < 50) {
    results.push({ json: {
      site_url: siteUrl, country_code: geo, widget_found: true,
      block_ids: input.block_ids, render_domain: renderDomain,
      proxy_url: input.proxy_url || '',
      teasers_found: 0, teasers: [],
      error: 'No render HTML after merge', scanned_at: input.scanned_at
    }});
    continue;
  }

  // Split merged HTML into individual renders
  const renderChunks = renderHtml.split('<!-- RENDER_SEPARATOR -->');
  const allTeasers = new Map();

  // Parse each render separately — position resets per render
  for (const chunk of renderChunks) {
    if (chunk.trim().length < 50) continue;
    const renderTeasers = parseSingleRender(chunk);
    for (const t of renderTeasers) {
      const key = t.media_id ? ('m:' + t.media_id) : ('t:' + t.title);
      if (!allTeasers.has(key)) {
        allTeasers.set(key, { ...t, appearances: 1 });
      } else {
        const existing = allTeasers.get(key);
        existing.appearances += 1;
        if (t.click_url) existing.click_url = t.click_url;
        if (t.position < existing.position) existing.position = t.position;
        if (t.image_url && !existing.image_url) existing.image_url = t.image_url;
      }
    }
  }

  const totalRenders = input.total_renders || renderChunks.length;
  const uniqueTeasers = Array.from(allTeasers.values());
  uniqueTeasers.forEach(t => {
    t.show_rate = parseFloat((t.appearances / totalRenders).toFixed(4));
  });

  results.push({ json: {
    site_url: siteUrl, country_code: geo, widget_found: true,
    block_ids: input.block_ids, render_domain: renderDomain,
    proxy_url: input.proxy_url || '',
    teasers_found: uniqueTeasers.length,
    total_renders: input.total_renders,
    renders_with_data: input.renders_with_data,
    teasers: uniqueTeasers,
    scanned_at: input.scanned_at
  }});
}

if (results.length === 0) {
