  const noIdTeasers = safeTeasers.filter(t => !t.media_id && t.title && typeof t.title === 'string' && t.title.length > 3);

  // --- New teasers: click up to MAX per site ---
  const toResolve = newTeasers.slice(0, MAX_RESOLVES_PER_SITE);
  const queuedNew = newTeasers.slice(MAX_RESOLVES_PER_SITE);

  toResolve.forEach(t => {
