  // --- Known teasers (not re-checked): use existing DB data ---
  knownTeasers.filter(t => !recheckIds.has(String(t.media_id))).forEach(t => {
    const dbRow = knownByMediaId.get(String(t.media_id));
    const existingUrl = dbRow ? dbRow.destination_url || '' : '';
    const params = parseTrackingParams(existingUrl);
