      needs_resolve: false, is_recheck: false,
      landing_url: null, landing_domain: null
    }});
  });

  // --- No-ID teasers ---
  noIdTeasers.forEach(t => {
    results.push({ json: {
      title: t.title, position: t.position,
      media_id: null, click_url: t.click_url || null,
      image_url: t.image_url || null,
