// Known showcase / feed patterns (checked against EVERY URL in redirect chain)
const SHOWCASE_PATTERNS = [
  /\/v1\/(full|short)\/\d+/,        // luckyfeed
  /\/feed\/[a-z0-9]+/i,             // generic feed TDS
  /smartfeed/i,                      // smartfeed
  /\/out\/[a-f0-9]{32}/i,           // news showcase hashes
];

function isShowcaseUrl(url) {
  for (const pat of SHOWCASE_PATTERNS) {
    if (pat.test(url)) return true;
  }
  return false;
}

// Manual URL param parser
function parseUrlParams(url) {
  if (!url || typeof url !== 'string') return { domain: null, params: {} };
  url = url.replace(/&amp;/g, '&');
  const domainMatch = url.match(/https?:\/\/([^/?#]+)/);
  const domain = domainMatch ? domainMatch[1] : null;
  const qIdx = url.indexOf('?');
  const p = {};
  if (qIdx !== -1) {
    url.substring(qIdx + 1).split('&').forEach(pair => {
      const eq = pair.indexOf('=');
      if (eq > 0) p[pair.substring(0, eq)] = decodeURIComponent(pair.substring(eq + 1));
    });
  }
  return { domain, params: p };
}

const isTrackerDomain = (url) => /render\.[a-zA-Z0-9-]+\.com/.test(url);
const STUB_DOMAINS = ['xfeedhub.com'];

const results = [];

for (let i = 0; i < httpItems.length; i++) {
  const httpResponse = httpItems[i].json;
  const teaser = (teaserItems[i] || teaserItems[teaserItems.length - 1] || { json: {} }).json;

  const statusCode = httpResponse.statusCode || httpResponse.code || 0;
  const headers = httpResponse.headers || {};
  const body = httpResponse.body || httpResponse.data || '';

  // Build redirect chain from the single HTTP response
  // (followRedirects=false, so we get the first redirect only)
  const chain = [];
  let landingUrl = '';

  // Original click URL
  chain.push(teaser.click_url || '');

  // Check Location header (301/302/307/308)
  if ([301, 302, 303, 307, 308].includes(statusCode)) {
    const location = headers.location || headers.Location || '';
    if (location && location.startsWith('http')) {
      chain.push(location);
      landingUrl = location;
    }
  }

  // Check response URL (if redirects were partially followed)
  if (httpResponse.url && !isTrackerDomain(httpResponse.url)) {
    chain.push(httpResponse.url);
    landingUrl = httpResponse.url;
  } else if (httpResponse.responseUrl && !isTrackerDomain(httpResponse.responseUrl)) {
    chain.push(httpResponse.responseUrl);
    landingUrl = httpResponse.responseUrl;
  }

  // Check HTML body for meta-refresh or JS redirects (TDS intermediate pages)
  if (typeof body === 'string' && body.length > 0) {
    let bodyRedirect = '';
    const metaMatch = body.match(/http-equiv=["']refresh["'][^>]*content=["'][^"']*url=([^"'\s>]+)/i);
    if (metaMatch) bodyRedirect = metaMatch[1].replace(/&amp;/g, '&');
    if (!bodyRedirect) {
      const jsMatch = body.match(/(?:window\.location|location\.href|location\.replace)\s*[=\(]\s*["']([^"']+)["']/i);
      if (jsMatch) bodyRedirect = jsMatch[1].replace(/&amp;/g, '&');
    }
    if (bodyRedirect && bodyRedirect.startsWith('http')) {
      chain.push(bodyRedirect);
      landingUrl = bodyRedirect;
    }
  }

  if (!landingUrl) landingUrl = 'resolve_failed';

  // Rate-limit stub domains
  const { domain, params: p } = parseUrlParams(landingUrl);
  if (domain && STUB_DOMAINS.some(d => domain === d || domain.endsWith('.' + d))) {
    landingUrl = 'rate_limited';
  }

  // Detect showcase by checking EVERY URL in the redirect chain
  let detectedType = 'landing';
  for (const url of chain) {
    if (url && isShowcaseUrl(url)) {
      detectedType = 'showcase';
      break;
    }
  }

  // Extract tracking params from final landing URL
  const trackingParams = landingUrl.startsWith('http') ? {
    landing_domain: domain,
    landing_type: detectedType,
    geozo_block_id: parseInt(p.blockid || p.block || p.BLOCK || p.block_id || p.BLOCK_ID || p.source || p.subid1 || p.c1 || p.c4) || null,
    geozo_site_id: parseInt(p.Siteid) || null,
    geozo_ad_id: parseInt(p.Adid || p.AD_ID || p.creative_id || p.subid2 || p.c2 || p.mpc3 || p.sid6) || null,
    geozo_adgroup_id: parseInt(p.adgroupid || p.ad_campaign_id || p.sid7 || p.c5 || p.utm_term) || null,
    cost: p.cost || p.BID || p.cs || p.price || null
  } : { landing_type: detectedType };

  results.push({ json: {
    title: teaser.title,
    position: teaser.position,
    media_id: teaser.media_id,
    click_url: teaser.click_url,
    image_url: teaser.image_url,
    short_description: teaser.short_description || null,
    full_description: teaser.full_description || null,
    button_text: teaser.button_text || null,
    render_domain: teaser.render_domain || null,
    landing_url: landingUrl,
    redirect_chain: chain.filter(u => u),
    ...trackingParams,
    show_rate: teaser.show_rate || 0,
    is_recheck: teaser.is_recheck || false,
    site_url: teaser.site_url,
    country_code: teaser.country_code,
    proxy_url: teaser.proxy_url || null
  }});
}

return results;

